private fun verifyStructuralMatch(node: AccessibilityNodeInfo?, pkg: String, target: String): Boolean {
    if (node == null) return false

    // 1. Setup Targets
    val parts = target.split("@@")
    val titleTarget = parts[0].trim()
    val summaryTarget = parts.getOrNull(1)?.trim()

    // 2. FAST ANCESTOR SEARCH (No rootInActiveWindow latency)
    var current: AccessibilityNodeInfo? = node
    var hasTitle = false
    var hasSummary = summaryTarget == null

    for (i in 0..5) {
        if (current == null) break
        if (!hasTitle && findTextInside(current, titleTarget)) hasTitle = true
        if (!hasSummary && summaryTarget != null && findTextInside(current, summaryTarget)) hasSummary = true

        if (hasTitle && hasSummary) break
        current = current.parent
    }

    if (hasTitle && hasSummary) {
        DebugLogger.log("TRAP_MATCH", "Fingerprint Verified via Ancestor Tree. Title=[$titleTarget]")
        return true
    }

    // 3. INTERSECTION SNIPER (Fallback)
    DebugLogger.log("UI_TRAP_VERBOSE", "Ancestor search failed. Engaging Intersection Sniper...")
    val root = rootInActiveWindow ?: return false
    val clickedBounds = android.graphics.Rect()
    node.getBoundsInScreen(clickedBounds)

    val screenNodes = root.findAccessibilityNodeInfosByText(titleTarget)
    var sniperMatch = false
    for (screenNode in screenNodes) {
        val textBounds = android.graphics.Rect()
        screenNode.getBoundsInScreen(textBounds)

        // Match if it intersects OR sits on the same horizontal row (+/- 100px)
        val intersects = android.graphics.Rect.intersects(clickedBounds, textBounds)
        val sameRow = Math.abs(textBounds.centerY() - clickedBounds.centerY()) < 100

        if (intersects || sameRow) {
            DebugLogger.log("UI_TRAP_SNIPER", "Found[$titleTarget] aligned with click at ${clickedBounds.toShortString()}")
            sniperMatch = true
            break
        }
    }

    if (sniperMatch) return true

    DebugLogger.log("UI_TRAP_REJECTED", "Title[$titleTarget] not found near click area.")
    return false
}

